{
    var components = string.Join(", ", go.GetComponents<UnityEngine.Component>().Select(c => c.GetType().Name));
    UnityEngine.Debug.Log($"  [{go.activeInHierarchy ? "ON" : "OFF"}] {go.name} (children:{go.transform.childCount}) components: {components}");
}

// Check what's under BuildSlots
