var scene = UnityEditor.SceneManagement.EditorSceneManager.GetActiveScene();
var roots = scene.GetRootGameObjects();

var towerSlots = new System.Collections.Generic.List<GameObject>();
var others = new System.Collections.Generic.List<GameObject>();

foreach (var go in roots)
{
    if (go.name.StartsWith("TowerSlot_"))
        towerSlots.Add(go);
    else
        others.Add(go);
}

UnityEngine.Debug.Log("=== Root Summary: " + roots.Length + " total ===");
UnityEngine.Debug.Log("TowerSlots at root: " + towerSlots.Count);
UnityEngine.Debug.Log("Other root objects: " + others.Count);

UnityEngine.Debug.Log("");
UnityEngine.Debug.Log("=== Non-TowerSlot root objects ===");
foreach (var go in others)
{
    var compNames = new System.Collections.Generic.List<string>();
    foreach (var c in go.GetComponents<UnityEngine.Component>())
        compNames.Add(c.GetType().Name);
    string components = string.Join(", ", compNames);
    string active = go.activeInHierarchy ? "ON" : "OFF";
    UnityEngine.Debug.Log("  [" + active + "] " + go.name + " (children:" + go.transform.childCount + ") comps: " + components);
}

var buildSlots = GameObject.Find("BuildSlots");
if (buildSlots != null)
{
    UnityEngine.Debug.Log("");
    UnityEngine.Debug.Log("=== BuildSlots children: " + buildSlots.transform.childCount + " ===");
    int count = Mathf.Min(buildSlots.transform.childCount, 5);
    for (int i = 0; i < count; i++)
        UnityEngine.Debug.Log("  " + buildSlots.transform.GetChild(i).name);
    if (buildSlots.transform.childCount > 5)
        UnityEngine.Debug.Log("  ... and " + (buildSlots.transform.childCount - 5) + " more");
}

var map = GameObject.Find("Map");
if (map != null)
{
    UnityEngine.Debug.Log("");
    UnityEngine.Debug.Log("=== Map hierarchy (depth 2) ===");
    Action<Transform, int> logTree = null;
    logTree = (t, depth) =>
    {
        string indent = new string(' ', depth * 2);
        UnityEngine.Debug.Log(indent + t.name + " (children:" + t.childCount + ")");
        if (depth < 2)
            for (int i = 0; i < t.childCount; i++)
                logTree(t.GetChild(i), depth + 1);
    };
    logTree(map.transform, 0);
}

var scene = UnityEditor.SceneManagement.EditorSceneManager.GetActiveScene();
var roots = scene.GetRootGameObjects();

// Collect root TowerSlots
var rootSlots = new System.Collections.Generic.List<GameObject>();
foreach (var go in roots)
    if (go.name.StartsWith("TowerSlot_"))
        rootSlots.Add(go);

// Collect BuildSlots children
var buildSlots = GameObject.Find("BuildSlots");
var buildSlotNames = new System.Collections.Generic.HashSet<string>();
var buildSlotPositions = new System.Collections.Generic.Dictionary<string, Vector3>();
if (buildSlots != null)
{
    for (int i = 0; i < buildSlots.transform.childCount; i++)
    {
        var child = buildSlots.transform.GetChild(i);
        buildSlotNames.Add(child.name);
        buildSlotPositions[child.name] = child.position;
    }
}

// Check overlap
int overlapCount = 0;
int uniqueToRoot = 0;
foreach (var slot in rootSlots)
{
    if (buildSlotNames.Contains(slot.name))
    {
        overlapCount++;
        // Check if positions match
        var rootPos = slot.transform.position;
        var buildPos = buildSlotPositions[slot.name];
        bool samePos = Vector3.Distance(rootPos, buildPos) < 0.01f;
        if (!samePos)
            UnityEngine.Debug.Log("DIFF pos: " + slot.name + " root=" + rootPos + " build=" + buildPos);
    }
    else
    {
        uniqueToRoot++;
    }
}

UnityEngine.Debug.Log("Root TowerSlots: " + rootSlots.Count);
UnityEngine.Debug.Log("BuildSlots children: " + buildSlotNames.Count);
UnityEngine.Debug.Log("Overlapping names: " + overlapCount);
UnityEngine.Debug.Log("Unique to root (not in BuildSlots): " + uniqueToRoot);

// Show a few unique ones
if (uniqueToRoot > 0)
{
    UnityEngine.Debug.Log("");
    UnityEngine.Debug.Log("=== Root TowerSlots NOT in BuildSlots ===");
    int shown = 0;
    foreach (var slot in rootSlots)
    {
        if (!buildSlotNames.Contains(slot.name))
        {
            UnityEngine.Debug.Log("  " + slot.name + " pos=" + slot.transform.position);
            shown++;
            if (shown >= 10) break;
        }
    }
}

// Check root Path vs Map/Grid/Path
var rootPath = GameObject.Find("/Path");
var gridPath = GameObject.Find("Map/Grid/Path");
if (rootPath != null && gridPath != null)
{
    UnityEngine.Debug.Log("");
    UnityEngine.Debug.Log("Root Path pos=" + rootPath.transform.position + " comps=" + rootPath.GetComponents<UnityEngine.Component>().Length);
    UnityEngine.Debug.Log("Grid Path pos=" + gridPath.transform.position + " comps=" + gridPath.GetComponents<UnityEngine.Component>().Length);
}

using UnityEngine;
using UnityEditor;
using UnityEditor.SceneManagement;

var scene = EditorSceneManager.GetActiveScene();
var roots = scene.GetRootGameObjects();

// Step 1: Delete old TowerSlots under BuildSlots (wrong positions from old cellSize)
var buildSlots = GameObject.Find("BuildSlots");
int deletedOld = 0;
if (buildSlots != null)
{
    var toDelete = new System.Collections.Generic.List<GameObject>();
    for (int i = 0; i < buildSlots.transform.childCount; i++)
        toDelete.Add(buildSlots.transform.GetChild(i).gameObject);
    foreach (var go in toDelete)
    {
        Object.DestroyImmediate(go);
        deletedOld++;
    }
}
Debug.Log("Step 1: Deleted " + deletedOld + " old TowerSlots from BuildSlots");

// Step 2: Collect root TowerSlots, deduplicate by name (keep first)
var rootSlots = new System.Collections.Generic.List<GameObject>();
foreach (var go in roots)
    if (go != null && go.name.StartsWith("TowerSlot_"))
        rootSlots.Add(go);

var seenNames = new System.Collections.Generic.HashSet<string>();
var duplicates = new System.Collections.Generic.List<GameObject>();
var uniqueSlots = new System.Collections.Generic.List<GameObject>();

foreach (var slot in rootSlots)
{
    if (seenNames.Add(slot.name))
        uniqueSlots.Add(slot);
    else
        duplicates.Add(slot);
}

Debug.Log("Step 2: Root TowerSlots=" + rootSlots.Count + " unique=" + uniqueSlots.Count + " duplicates=" + duplicates.Count);

// Delete duplicates
foreach (var dup in duplicates)
    Object.DestroyImmediate(dup);
Debug.Log("Step 2b: Deleted " + duplicates.Count + " duplicate root TowerSlots");

// Step 3: Move unique root TowerSlots under BuildSlots
if (buildSlots != null)
{
    foreach (var slot in uniqueSlots)
        slot.transform.SetParent(buildSlots.transform, true); // worldPositionStays
    Debug.Log("Step 3: Moved " + uniqueSlots.Count + " TowerSlots under BuildSlots");
}

// Step 4: Move loose objects under Map/Decorations
var mapObj = GameObject.Find("Map");
if (mapObj != null)
{
    // Find or create Decorations
    var decTransform = mapObj.transform.Find("Decorations");
    if (decTransform == null)
    {
        var dec = new GameObject("Decorations");
        dec.transform.SetParent(mapObj.transform, false);
        decTransform = dec.transform;
    }

    // Move 薯条
    var fries = GameObject.Find("/\u85AF\u6761");
    if (fries != null)
    {
        fries.transform.SetParent(decTransform, true);
        Debug.Log("Step 4a: Moved 薯条 under Map/Decorations");
    }

    // Move fortress_skull
    var skull = GameObject.Find("/fortress_skull");
    if (skull != null)
    {
        skull.transform.SetParent(decTransform, true);
        Debug.Log("Step 4b: Moved fortress_skull under Map/Decorations");
    }
}

// Step 5: Move root Path under Map (as sibling of Grid)
var rootPath = GameObject.Find("/Path");
if (rootPath != null && mapObj != null)
{
    rootPath.transform.SetParent(mapObj.transform, true);
    Debug.Log("Step 5: Moved root Path under Map");
}

// Verify final state
roots = scene.GetRootGameObjects();
Debug.Log("");
Debug.Log("=== Final root objects (" + roots.Length + ") ===");
foreach (var go in roots)
    Debug.Log("  " + go.name + " (children:" + go.transform.childCount + ")");

// Mark scene dirty
EditorSceneManager.MarkSceneDirty(scene);
Debug.Log("Scene marked dirty - remember to save!");

using UnityEngine;
using UnityEditor;
using UnityEditor.SceneManagement;

var scene = EditorSceneManager.GetActiveScene();
var roots = scene.GetRootGameObjects();

// Find fortress_skull (inactive, so Find won't work - search roots)
GameObject skull = null;
foreach (var go in roots)
{
    if (go.name == "fortress_skull")
    {
        skull = go;
        break;
    }
}

if (skull != null)
{
    var mapObj = GameObject.Find("Map");
