        {
            var dec = new GameObject("Decorations");
            dec.transform.SetParent(mapObj.transform, false);
            decTransform = dec.transform;
        }
        skull.transform.SetParent(decTransform, true);
        Debug.Log("Moved fortress_skull under Map/Decorations");
    }
}

// Verify final hierarchy
roots = scene.GetRootGameObjects();
Debug.Log("=== Final root objects (" + roots.Length + ") ===");
