if (map != null)
{
    Debug.Log("");
    Debug.Log("=== Map hierarchy ===");
    Action<Transform, int> showTree = null;
    showTree = (t, depth) =>
    {
        string indent = new string(' ', depth * 2);
        Debug.Log(indent + t.name + " (children:" + t.childCount + ")");
        if (depth < 2)
            for (int i = 0; i < t.childCount; i++)
                showTree(t.GetChild(i), depth + 1);
