    var pathCreator = pathObj.GetComponent<TowerDefense.Utils.PathCreator>();
    if (pathCreator != null)
    {
        var waypoints = pathCreator.Waypoints;
        Debug.Log("Before: waypoint[0] = " + waypoints[0] + " count=" + waypoints.Count);

        // Scale all waypoints by 1/64 (old cellSize was 64, new is 1)
        var serialized = new SerializedObject(pathCreator);
        var wpProp = serialized.FindProperty("_waypoints");

        if (wpProp != null && wpProp.isArray)
        {
            for (int i = 0; i < wpProp.arraySize; i++)
            {
                var elem = wpProp.GetArrayElementAtIndex(i);
                var old = elem.vector3Value;
                var scaled = new Vector3(old.x / 64f, old.y / 64f, old.z / 64f);
                elem.vector3Value = scaled;
            }
            serialized.ApplyModifiedProperties();
        }

        // Verify
        Debug.Log("After: waypoint[0] = " + waypoints[0]);
        Debug.Log("After: waypoint[last] = " + waypoints[waypoints.Count - 1]);

        // Show all scaled waypoints
        Debug.Log("=== Scaled waypoints ===");
        for (int i = 0; i < waypoints.Count; i++)
            Debug.Log("  [" + i + "] = " + waypoints[i].ToString("F2"));

